-- Create ENUM types for terminal
DO $$ 
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'intake_access_role') THEN
    CREATE TYPE intake_access_role AS ENUM ('attorney', 'staff', 'viewer');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'terminal_message_role') THEN
    CREATE TYPE terminal_message_role AS ENUM ('user', 'assistant', 'system');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'discovery_draft_type') THEN
    CREATE TYPE discovery_draft_type AS ENUM ('requests', 'witness_topics', 'esi_plan', 'proof_matrix', 'other');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'discovery_task_status') THEN
    CREATE TYPE discovery_task_status AS ENUM ('pending', 'in_progress', 'completed', 'cancelled');
  END IF;
  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'discovery_task_priority') THEN
    CREATE TYPE discovery_task_priority AS ENUM ('low', 'medium', 'high', 'urgent');
  END IF;
END $$;

